create extension if not exists pgcrypto;
create type pet_species as enum ('dog','cat','rabbit','bird','other');create type treatment_type as enum ('flea_tick','worming','heartworm','vaccination','medication','grooming','vet_checkup','other');
create table profiles(user_id uuid primary key references auth.users on delete cascade,email text not null,is_premium boolean not null default false,stripe_customer_id text,stripe_subscription_id text,premium_until timestamptz,reminder_leads int[] not null default '{3,0}',email_reminders_enabled boolean not null default true,created_at timestamptz not null default now());
create table pets(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users on delete cascade,name text not null check(length(name) between 1 and 60),species pet_species not null,photo_path text,birth_date date,weight_kg numeric check(weight_kg>0),created_at timestamptz not null default now());
create table treatments(id uuid primary key default gen_random_uuid(),pet_id uuid not null references pets on delete cascade,user_id uuid not null references auth.users on delete cascade,name text not null,type treatment_type not null,last_given date not null,interval_days int not null check(interval_days between 1 and 1095),product_name text,product_photo_path text,notes text,next_due date generated always as (last_given+interval_days) stored,created_at timestamptz not null default now());
create table treatment_log(id uuid primary key default gen_random_uuid(),treatment_id uuid not null references treatments on delete cascade,user_id uuid not null references auth.users on delete cascade,done_at timestamptz not null default now(),given_product text);
create table vet_visits(id uuid primary key default gen_random_uuid(),pet_id uuid not null references pets on delete cascade,user_id uuid not null references auth.users on delete cascade,date date not null,reason text not null,notes text,cost_cents int check(cost_cents>=0));
create table email_events(id uuid primary key default gen_random_uuid(),user_id uuid not null references auth.users on delete cascade,sent_at timestamptz not null default now(),type text not null,payload jsonb not null default '{}',unique(user_id,type));
create table stripe_events(id text primary key,processed_at timestamptz not null default now());
create table events(id bigint generated always as identity primary key,user_id uuid references auth.users on delete set null,name text not null check(name in ('signup','pet_created','treatment_created','marked_done','paywall_viewed','checkout_started','upgraded')),created_at timestamptz not null default now());
create or replace function public.new_profile() returns trigger language plpgsql security definer set search_path=public as $$begin insert into profiles(user_id,email) values(new.id,coalesce(new.email,''));return new;end$$;create trigger auth_profile after insert on auth.users for each row execute function public.new_profile();
create or replace function mark_treatment_done(p_treatment_id uuid,p_done_at timestamptz) returns void language plpgsql security invoker as $$declare p treatments;begin select * into p from treatments where id=p_treatment_id and user_id=auth.uid();if not found then raise exception 'not found';end if;insert into treatment_log(treatment_id,user_id,done_at,given_product) values(p.id,p.user_id,p_done_at,p.product_name);update treatments set last_given=p_done_at::date where id=p.id;insert into events(user_id,name) values(auth.uid(),'marked_done');end$$;
alter table profiles enable row level security;alter table pets enable row level security;alter table treatments enable row level security;alter table treatment_log enable row level security;alter table vet_visits enable row level security;alter table email_events enable row level security;alter table events enable row level security;
create policy own_profiles on profiles for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy own_pets on pets for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy own_treatments on treatments for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy own_logs on treatment_log for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy own_visits on vet_visits for all using(auth.uid()=user_id) with check(auth.uid()=user_id);create policy own_emails on email_events for select using(auth.uid()=user_id);create policy own_events on events for select using(auth.uid()=user_id);
create unique index one_digest on email_events(user_id,type);create index treatment_due on treatments(next_due);create index pets_user on pets(user_id);
create or replace function due_reminder_digest(p_today date) returns table(user_id uuid,email text,items jsonb) language sql security definer set search_path=public as $$select p.user_id,p.email,jsonb_agg(jsonb_build_object('pet_name',pet.name,'name',t.name,'product_name',t.product_name,'days',t.next_due-p_today)) from profiles p join treatments t on t.user_id=p.user_id join pets pet on pet.id=t.pet_id where p.email_reminders_enabled and ((t.next_due-p_today)=any(p.reminder_leads) or t.next_due-p_today=-2) group by p.user_id,p.email$$;
